string reverseWords(string s)
{
    stringstream ss(s);
    string word;
    vector<string> words;

    while (ss >> word) words.push_back(word);

    string result;
    for (int i = words.size() - 1; i >= 0; i--)
    {
        result += words[i];
        if (i != 0) result += " ";
    }

    return result;
}

int main()
{
    cout << reverseWords("the sky is blue") << endl;

    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>

using namespace std;

string reverseWords(string s)
{
    reverse(s.begin(), s.end()); // whole string reversed: "eulb si yks eht"

    int write = 0;
    int n = s.size();
    int i = 0;

    while (i < n)
    {
        if (s[i] != ' ')
        {
            if (write != 0) s[write++] = ' ';

            int wordStart = write;
            while (i < n && s[i] != ' ')
            {
                s[write++] = s[i++];
            }

            reverse(s.begin() + wordStart, s.begin() + write); // un-reverse this word
        }
        else
        {
            i++;
        }
    }

    s.resize(write);
    return s;
}

int main()
{
    cout << reverseWords("the sky is blue") << endl;

    return 0;
}

