int compress(vector<char> &chars)
{
    string result;
    int i = 0;

    while (i < (int)chars.size())
    {
        char c = chars[i];
        int count = 0;
        while (i < (int)chars.size() && chars[i] == c)
        {
            count++;
            i++;
        }

        result += c;
        if (count > 1) result += to_string(count);
    }

    for (int j = 0; j < (int)result.size(); j++) chars[j] = result[j];

    return result.size();
}

int main()
{
    vector<char> chars = {'a', 'a', 'b', 'b', 'c', 'c', 'c'};

    int len = compress(chars);
    cout << len << endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>

using namespace std;

int compress(vector<char> &chars)
{
    int write = 0;
    int read = 0;

    while (read < (int)chars.size())
    {
        char c = chars[read];
        int count = 0;

        while (read < (int)chars.size() && chars[read] == c)
        {
            count++;
            read++;
        }

        chars[write++] = c;

        if (count > 1)
        {
            for (char digit : to_string(count))
            {
                chars[write++] = digit;
            }
        }
    }

    return write;
}

int main()
{
    vector<char> chars = {'a', 'a', 'b', 'b', 'c', 'c', 'c'};

    int len = compress(chars);
    cout << len << endl;

    return 0;
}

